public int knightDialer(int n) {
    if (n == 1) return 10;
    final int MOD = 1000000007;
    int[][] moves = {
        {4, 6}, {6, 8}, {7, 9}, {4, 8}, {0, 3, 9},
        {}, {1, 7, 0}, {2, 6}, {1, 3}, {2, 4}
    };
    int[] dp = new int[10];
    Arrays.fill(dp, 1);
    for (int i = 2; i <= n; ++i) {
        int[] new_dp = new int[10];
        for (int j = 0; j < 10; ++j)
            for (int move : moves[j])
                new_dp[j] = (new_dp[j] + dp[move]) % MOD;
        dp = new_dp;
    }
    return Arrays.stream(dp).reduce(0, (a, b) -> (a + b) % MOD);
}
